import pytest
from typing import List


def intersection(lst1: list, lst2: list) -> list:
    set2 = set(lst2)
    seen = set()
    result = []
    for item in lst1:
        if item in set2 and item not in seen:
            result.append(item)
            seen.add(item)
    return result


